window.__QUIZ_DATA__=[{"id":"theory>Physics>2018>1>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Define strain","images":[],"marking_scheme":"Strain is defined as the ratio of the extension to the original length (e/l).","marks":"1","difficulty":"1"},{"id":"theory>Physics>2018>1>b","subject":"Physics","year":"2018","type":"Theory","sub_label":"b","group":"FINAL","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A rubber and is stretched to twice its original length. Calculate the strain on the rubber band.","images":[],"marking_scheme":"Let original length be X  new length be 2X  extension = 2X - X= X  Strain=el=xx= 1","marks":"2","difficulty":"2"},{"id":"theory>Physics>2018>2","subject":"Physics","year":"2018","type":"Theory","sub_label":"2","group":"CLOSENESS","topic":"FIBRE OPTICS :","question":"State three materials used for making optical fibres","images":[],"marking_scheme":"- Silica  - Germanra  - Fluoroaluminate","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>3","subject":"Physics","year":"2018","type":"Theory","sub_label":"3","group":"CLOSENESS","topic":"MAGNETIC MATERIALS :","question":"Name three classes of magnetic materials","images":[],"marking_scheme":"- Diamagnetism  - Ferromagnetism  - Paramagnetism","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>4>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRICAL CONDUCTION THROUGH MATERIALS [ELECTRONIC] :","question":"What is an intrinsic semiconductor?","images":[],"marking_scheme":"An Intrinsic semiconductor is an undoped semiconductor, pure without any significant odepart species present.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2018>4>b","subject":"Physics","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Distinguish between the p-type and n-type semiconductors","images":[],"marking_scheme":"P-type semiconductors are these produced by doping with indium or boron so as to produce an impure semiconductor with more holes or positive charges than electron while an n-type semiconductor are those produced by doping with germanium or arsenic so as to produce an impure semiconductor with more free electrons or negative charges than positive charges.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2018>5","subject":"Physics","year":"2018","type":"Theory","sub_label":"5","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A missile is projected so as to attain its maximum range. Calculate the maximum height attained if the initial velocity of projection is 200 ms-1  (Leaving the answer in whole number)","images":[],"marking_scheme":"V = 200ms-1  g = 10ms-2  H=U2Sin2\u03b82g  \u03b8 = 45\u00b0 (since maximum range is obtained at this angle)  H=2w2Sin24520  =400 \u00d7 0.520 = 1000m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>6","subject":"Physics","year":"2018","type":"Theory","sub_label":"6","group":"","topic":"SOLAR ENERGY COLLECTOR AND BLACK BODY RADIATION. :","question":"A black body radiates maximum energy when its surface temperature T and the corresponding wavelength \u22cemax T = constant     Given the values of the constant and surface temperature as 2.9 x 10-3 mK and 570C respectively.   Calculate the frequency of the energy radiated","images":["data:image/png;base64,"],"marking_scheme":"\u03bbmaxT = constant  T = 57\u00b0C = 330K","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>7>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INTRODUCTION TO LASER :","question":"What does the acronym LASER stands for?","images":[],"marking_scheme":"Light Amplification by Stimulate Emission of Radiation","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>7>b","subject":"Physics","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"INTRODUCTION TO LASER :","question":"What is a laser?","images":[],"marking_scheme":"A laser is a device that emits light through a process of optical amplification based on the stimulated emission of electromagnetic radiation.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>8>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"Define uniform acceleration","images":[],"marking_scheme":"Uniform acceleration can be defined as when the velocity of a moving body increases by equal amounts in equal time intervals.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2018>8>b>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MOTION : TYPES OF FORCE","question":"Forces act on a car in motion. List the:    horizontal forces and their directions;","images":[],"marking_scheme":"Frictional force - opposite driving force  Driving force - forward","marks":"2","difficulty":"2"},{"id":"theory>Physics>2018>8>b>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MOTION : TYPES OF FORCE","question":"Forces act on a car in motion. List the:  vertical forces and their directions","images":[],"marking_scheme":"Gravitational force - Downward  Reactive force - Upward","marks":"2","difficulty":"2"},{"id":"theory>Physics>2018>8>c>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"","topic":"SPEED AND VELOCITY : VELOCITY-TIME GRAPH","question":"A car starts from rest and accelerates uniformly for 20 s to attain a speed of 25 ms-2. It maintains this speed for 30 s before decelerating uniformly to rest. The total time for the journey is 60 s.    Sketch a velocity - time graph for the motion.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Physics>2018>8>c>ii>A","subject":"Physics","year":"2018","type":"Theory","sub_label":"A","group":"FINAL","topic":"SPEED AND VELOCITY : VELOCITY-TIME GRAPH","question":"Use the graph to determine the:  total distance travelled by the car   (Leaving the answer in whole number)","images":[],"marking_scheme":"Distance travelled = Area of the trapezium  =12(RS+PQ)\u00d7h  =12(60+30)\u00d725  =12\u00d790\u00d725 = 1125m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>8>c>ii>B","subject":"Physics","year":"2018","type":"Theory","sub_label":"B","group":"FINAL","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"deceleration of the car.   (Leaving the answer in three decimal place)","images":[],"marking_scheme":"Deceleration=QTTS=2510=2.5ms-1","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>8>d","subject":"Physics","year":"2018","type":"Theory","sub_label":"d","group":"FINAL","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"The figure above illustrate force - extension graph for a stretched spiral spring. Determine the work done on the spring.   (Leaving the answer in three decimal place)","images":["data:image/png;base64,"],"marking_scheme":"Workdone = Area of Triangle  =12\u00d7base\u00d7height  =12\u00d70.5\u00d712 = 3Ncm-1 or 0.03Nm-1","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>9>a>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"List two factors that affects heat loss by:  (i)radiation","images":[],"marking_scheme":"- Surface  area  - Rate of atomic activity","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>9>a>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"convection","images":[],"marking_scheme":"Nature/type of fluid  Density/viscosity of fluid  Thermal conductivity of fluid  Specific heat capacity of fluid  Exposed surface area","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>9>b","subject":"Physics","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT CAPACITY","question":"State two factors that determine the quantity of heat in a body","images":[],"marking_scheme":"- Specific heat capacity of the body  - Temperature change of the body","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>9>c","subject":"Physics","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"Explain the statement: The specific latent heat of vaporization of mercury is 2.72 x 105 J kg-1","images":[],"marking_scheme":"It means 2072 \u00d7 105J is required to vaporise a unit mass of mercury without a change in temperature.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>9>d>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A jug of heat capacity 250 JK-1 contains water at 28 0C. An electric heater of resistance 35 ohm connected to a 220 V source is to raise the temperature of the water until it boils at 1000C in 4 minutes. After another 5 minutes, 300 g of water has evaporated. Assuming no heat is lost to the surrounding, calculate the:    Mass of water in the jug before heating","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>9>d>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"A jug of heat capacity 250 JK-1 contains water at 28 0C. An electric heater of resistance 35 ohm connected to a 220 V source is to raise the temperature of the water until it boils at 1000C in 4 minutes. After another 5 minutes, 300 g of water has evaporated. Assuming no heat is lost to the surrounding, calculate the:   specific latent heat of vaporization","images":[],"marking_scheme":"Energy supplied=v2tR  v = 220V, R = 35 ohms, it evaporated for 5 minutes, t = 60 \u00d7 5 = 300s, m = 300g = 0.3kg  2202\u00d730035=414857.1429J  H = mL  L=Hm  L = 414857.1429/0.3 = 1382857.143Jkg-1  L = 1.38 \u00d7 106Jkg-1","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>10>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PROPERTIES OF WAVES : DIFFRACTION","question":"Define diffraction","images":[],"marking_scheme":"Diffraction is the ability of waves to bend around obstacles in their path.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>10>b>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Explain critical angle","images":[],"marking_scheme":"Critical angle is the angle of incidence in the denser medium when the angle of refraction in the less dense medium is 90\u00b0","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>10>b>ii>A","subject":"Physics","year":"2018","type":"Theory","sub_label":"A","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The diagram above illustrates a ray of light passing through a rectangular transparent plastic block.    Determine the value of the critical angle.","images":["data:image/png;base64,"],"marking_scheme":"Critical angle = 46\u00b0","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>10>b>ii>B","subject":"Physics","year":"2018","type":"Theory","sub_label":"B","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The diagram above illustrates a ray of light passing through a rectangular transparent plastic block.   Calculate the refractive index of the block.","images":["data:image/png;base64,"],"marking_scheme":"Refractiveindex=1sinC  R.I=1sin46 = 1.39","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>10>c>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"FINAL","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"A pipe closed at one end has fundamental frequency of 200 Hz. The frequency of the first overtone of the closed pipe is equal to the frequency of the first overtone of an open pipe.   Calculate the:    fundamental frequency of the open pipe  (Leaving the answer in whole number)","images":[],"marking_scheme":"fo = 200Hz  First overtone = 3Fo = 3 \u00d7 200 = 600Hz  1st Overtone (open pipe) = 600Hz  Fundamentalovertone=1st Overtone2  =6002=300Hz","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>10>c>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"FINAL","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"length of the closed pipe  (Leaving the answer in three decimal place)","images":[],"marking_scheme":"Fo=V4l  200=3304l  l=330200\u00d74 = 0.413m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>10>c>iii","subject":"Physics","year":"2018","type":"Theory","sub_label":"iii","group":"FINAL","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"length of the open pipe  (Leaving the answer in two decimal place)","images":[],"marking_scheme":"F1=Vl  600=330l  l=330600=0.55m","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>11>a>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"Define reactance","images":[],"marking_scheme":"Reactance can be defined as the opposition to the flow of a.c offered by a capacitor or an inductor or both.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>11>a>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"Define impedance in an a.c circuit","images":[],"marking_scheme":"Impedance is the overall opposition of a mixed circuit containing a resistor an inductor and/or a capacitor.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2018>11>b>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"The diagram above illustrates an a.c. generator. When the coil is rotated, e.m.f. is reduced in the coil.    Explain why an e.m.f. is induced","images":["data:image/png;base64,"],"marking_scheme":"An e.m.f is induced because the plane or the coil is parallel to the field, thereby causing a change of flux at maximum.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>11>b>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT","question":"The diagram above illustrates an a.c. generator. When the coil is rotated, e.m.f. is reduced in the coil.   State the purpose of the slip-rings","images":["data:image/png;base64,"],"marking_scheme":"The purpose of the slip rings is to obtain an alternating voltage.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>11>b>iii","subject":"Physics","year":"2018","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"The diagram above illustrates an a.c. generator. When the coil is rotated, e.m.f. is reduced in the coil.   Name and state the law used to determine the direction of the induced current","images":["data:image/png;base64,"],"marking_scheme":"Flemings Right Hand Rule: It states that if the thumb, fore finger and middle ringer of the right hand are held mutually at right angles to each other, with the fore-finger pointing in the direction of motion, then the middle finger will point in the induced emf or current direction.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>11>b>iv","subject":"Physics","year":"2018","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"State two ways to increase the induced e.m.f.","images":[],"marking_scheme":"- Increase the number of turns in the coil  - Increase the area of the coil.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>11>c","subject":"Physics","year":"2018","type":"Theory","sub_label":"c","group":"FINAL","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"A lamp is rated 12 V, 6 W. Calculate the amount of energy of transformed by the lamp in 5 minutes.","images":[],"marking_scheme":"E= Power \u00d7 time  \u2234 =6 \u00d7 5 \u00d760  = 1800J","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>12>a","subject":"Physics","year":"2018","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"Define binding energy in an atom","images":[],"marking_scheme":"Binding energy is the minimum work/energy required to seperate the nucleons of an atom.","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>12>b","subject":"Physics","year":"2018","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"List three evidence to support the claim that X-rays are electromagnetic waves.","images":[],"marking_scheme":"Required Evidence:  - Not affected by electric/magnetic fields  - Can travel through a vacuum  - Travels with the speed of light   - Can be polarized  - Cause Flourescence","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>12>c","subject":"Physics","year":"2018","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"List three peaceful uses of nuclear energy","images":[],"marking_scheme":"- General electricity   - Treatment of Tumor  - Power submarine/rockets","marks":"3","difficulty":"2"},{"id":"theory>Physics>2018>12>d>i","subject":"Physics","year":"2018","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelength 4.5 x 10-7m is incident on a metal resulting in the emission of photo electrons. If the work function of the metal is 3.0 x 10-19 J, calculate the:   [Speed of light = 3.0 x 108 ms-1, h = 6.6 x 10-34 Js]    frequency of the incident light;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>12>d>ii","subject":"Physics","year":"2018","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelength 4.5 x 10-7m is incident on a metal resulting in the emission of photo electrons. If the work function of the metal is 3.0 x 10-19 J, calculate the:   [Speed of light = 3.0 x 108 ms-1, h = 6.6 x 10-34 Js]  energy of the incident light;","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>2018>12>d>iii","subject":"Physics","year":"2018","type":"Theory","sub_label":"iii","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"Light of wavelength 4.5 x 10-7m is incident on a metal resulting in the emission of photo electrons. If the work function of the metal is 3.0 x 10-19 J, calculate the:   [Speed of light = 3.0 x 108 ms-1, h = 6.6 x 10-34 Js]  energy of the photoelectrons.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"}];